def check_function_returns_value(node):
    # Skip special methods and test methods
    name = node.get('name', '')
    if name.startswith('test_') or name.startswith('__'):
        return False

    # Skip if function has decorators
    if node.get('decorator_list'):
        return False

    # Don't check constructors
    if name == '__init__':
        return False

    # Check function body for returns with values
    for stmt in node.get('body', []):
        if not isinstance(stmt, dict):
            continue

        # Found a return with a value
        if stmt.get('node_type') == 'Return' and stmt.get('value'):
            return False

        # Function has side effects like print or global
        if stmt.get('node_type') == 'Global':
            return False
        if stmt.get('node_type') == 'Expr' and isinstance(stmt.get('value'), dict) and stmt['value'].get('node_type') == 'Call':
            return False

    # No proper return value found and no side effects detected
    return True
